"use client";
import React from "react";

interface Props {
 id: number;
 name: string;
 weight: string;
 price: number;
 oldPrice?: number;
 discount?: string;
 image: string;
 onAdd: () => void;
}

const ProductCard: React.FC<Props> = ({ name, weight, price, oldPrice, discount, image, onAdd }) => (
 <div
  className="group relative flex flex-col bg-white p-4 transition-all duration-300 ease-out cursor-pointer hover:bg-[#F9F9F9]"
 >
  {/* ── Minimalist Price Badge for Coffee style ── */}
  {discount && (
   <div className="absolute top-4 left-4 z-20 rounded-md bg-meren-black px-2 py-0.5 text-[9px] font-black tracking-widest text-white uppercase font-manrope">
    {discount}
   </div>
  )}

  {/* ── Clean Hero Image ── */}
  <div className="relative mb-4 flex aspect-square items-center justify-center overflow-hidden rounded-2xl bg-[#f2f2f2] transition-colors duration-500 group-hover:bg-[#ebebeb]">
   <img
    src={image}
    alt={name}
    loading="lazy"
    className="h-[85%] w-[85%] object-contain mix-blend-multiply transition-transform duration-700 ease-out-premium group-hover:scale-110"
   />

   {/* Subtle Bottom-Right Add Button */}
   <button
    onClick={(e) => { e.stopPropagation(); onAdd(); }}
    className="absolute bottom-3 right-3 flex h-9 w-9 items-center justify-center rounded-full bg-white text-meren-black shadow-md border border-black/5 opacity-0 translate-y-2 transition-all duration-300 group-hover:opacity-100 group-hover:translate-y-0 hover:bg-meren-black hover:text-white"
   >
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round">
     <path d="M12 5v14M5 12h14" />
    </svg>
   </button>
  </div>

  {/* ── Minimalist Info (Coffee Grid Style) ── */}
  <div className="flex flex-col font-manrope">
   <p className="text-[14px] font-extrabold leading-tight text-meren-black tracking-tight mb-1 line-clamp-1">
    {name}
   </p>

   <div className="flex items-baseline gap-2">
    <p className="text-[13px] font-bold text-meren-black">
     {price} ₽
    </p>
    {oldPrice && (
     <p className="text-[11px] font-medium text-[#AEAEB2] line-through">
      {oldPrice} ₽
     </p>
    )}
    <p className="text-[10px] font-medium text-[#AEAEB2] lowercase ml-auto">
     {weight}
    </p>
   </div>
  </div>
 </div>
);

export default ProductCard;
