"use client"
import React from "react"
import { CartItem } from "@/app/page"

interface Props {
 cart: CartItem[]
 onUpdateQuantity: (id: number, delta: number) => void
 total: number
}

const CartSidebar: React.FC<Props> = ({ cart, onUpdateQuantity, total }) => {
 return (
  <div className="flex flex-col h-full bg-white rounded-3xl border border-black/5 font-manrope">

   {/* ── Minimalist Header ── */}
   <div className="p-6 border-b border-black/5">
    <h2 className="text-[20px] font-black tracking-tighter text-meren-black lowercase">корзина</h2>
    <p className="text-[10px] font-bold text-[#AEAEB2] uppercase tracking-widest mt-1">твоя подборка</p>
   </div>

   {/* ── Body ── */}
   <div className="flex-1 overflow-y-auto px-6 py-4 smooth-scroll">
    {cart.length === 0 ? (
     <div className="flex h-full flex-col items-center justify-center p-10 opacity-30 grayscale cursor-default select-none">
      <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" className="mb-4">
       <path d="M6 2 3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z" /><path d="M3 6h18" /><path d="M16 10a4 4 0 0 1-8 0" />
      </svg>
      <p className="text-[11px] font-black text-center uppercase tracking-widest">пусто</p>
     </div>
    ) : (
     <div className="flex flex-col gap-6">
      {cart.map((item) => (
       <div key={item.id} className="group flex items-center gap-4">
        {/* Minimal Thumbnail */}
        <div className="h-14 w-14 shrink-0 overflow-hidden rounded-xl bg-[#F5F5F7] p-2 transition-colors group-hover:bg-[#EBEBF0]">
         <img src={item.image} alt="" className="h-full w-full object-contain mix-blend-multiply" />
        </div>

        {/* Name & Control */}
        <div className="flex-1 min-w-0">
         <p className="text-[13px] font-bold tracking-tight text-meren-black leading-tight line-clamp-1 mb-1">
          {item.name}
         </p>

         <div className="flex items-center gap-3">
          <div className="flex items-center gap-2 rounded-full border border-black/5 px-2 py-0.5 bg-[#F5F5F7]">
           <button
            onClick={() => onUpdateQuantity(item.id, -1)}
            className="text-[14px] font-bold text-[#AEAEB2] hover:text-meren-black cursor-pointer border-none bg-transparent"
           >—</button>
           <span className="text-[11px] font-black text-meren-black min-w-[12px] text-center">{item.quantity}</span>
           <button
            onClick={() => onUpdateQuantity(item.id, 1)}
            className="text-[14px] font-bold text-[#AEAEB2] hover:text-meren-black cursor-pointer border-none bg-transparent"
           >+</button>
          </div>
         </div>
        </div>

        {/* Price */}
        <div className="text-right">
         <p className="text-[14px] font-black tracking-tight text-meren-black">
          {item.price * item.quantity} ₽
         </p>
        </div>
       </div>
      ))}
     </div>
    )}
   </div>

   {/* ── Footer ── */}
   {cart.length > 0 && (
    <div className="p-6 border-t border-black/5 bg-[#F9F9FB]">
     <div className="flex items-end justify-between mb-6">
      <span className="text-[11px] font-black text-[#AEAEB2] uppercase tracking-[0.2em]">итого</span>
      <div className="text-right">
       <span className="text-[32px] font-black text-meren-black tracking-tighter leading-none">{total}</span>
       <span className="text-[16px] font-black text-meren-black/30 ml-1 italic">₽</span>
      </div>
     </div>

     <button className="w-full rounded-2xl bg-meren-black py-4 text-[13px] font-black uppercase tracking-widest text-white transition-all hover:bg-meren-orange hover:scale-[1.02] active:scale-[0.98] border-none cursor-pointer shadow-bold">
      Оформить заказ
     </button>

     <p className="mt-4 text-center text-[10px] font-bold text-[#AEAEB2] uppercase tracking-tighter opacity-70">
      бесплатная доставка от 1500 ₽
     </p>
    </div>
   )}

  </div>
 )
}

export default CartSidebar
